package com.recettealarm.app;
import android.app.*;import android.media.*;import android.os.*;import android.provider.Settings;import android.graphics.Typeface;import android.view.*;import android.widget.*;
public class AlarmActivity extends Activity{MediaPlayer mp;Vibrator vib;Handler handler=new Handler();TextView warn;public void onCreate(Bundle b){super.onCreate(b);getWindow().addFlags(WindowManager.LayoutParams.FLAG_KEEP_SCREEN_ON|WindowManager.LayoutParams.FLAG_SHOW_WHEN_LOCKED|WindowManager.LayoutParams.FLAG_TURN_SCREEN_ON|WindowManager.LayoutParams.FLAG_DISMISS_KEYGUARD);LinearLayout r=UI.root(this);r.addView(UI.center(this,"🔔",64,Typeface.BOLD));r.addView(UI.center(this,"TEMPS ÉCOULÉ !",34,Typeface.BOLD));r.addView(UI.center(this,safe(getIntent().getStringExtra("title")),18,Typeface.BOLD));LinearLayout box=UI.section(this);box.setBackground(UI.stroke(0xffffffff,UI.dp(this,28),UI.danger));box.addView(UI.center(this,"ANTI-BRÛLURE",15,Typeface.BOLD));box.addView(UI.center(this,safe(getIntent().getStringExtra("note")),24,Typeface.BOLD));r.addView(box);Button stop=UI.btn(this,"■ ARRÊTER L'ALARME");Button plus=UI.whiteBtn(this,"+5 MINUTES");Button ok=UI.oliveBtn(this,"✅ J'ai vérifié le plat");r.addView(stop);r.addView(plus);r.addView(ok);warn=UI.center(this,"⚠ Vérifie la cuisson maintenant.",14,Typeface.BOLD);warn.setTextColor(UI.danger);r.addView(warn);startNoise();handler.postDelayed(()->warn.setText("⚠ Attention : le plat risque de brûler."),30000);handler.postDelayed(()->restartNoise(),60000);stop.setOnClickListener(v->finish());ok.setOnClickListener(v->finish());plus.setOnClickListener(v->{AlarmReceiver.schedule(this,5*60_000L,"Rappel +5 minutes : vérifie le plat","Rappel cuisson");finish();});}
 String safe(String s){return s==null||s.trim().isEmpty()?"Vérifier la cuisson et remuer le plat immédiatement.":s;}void startNoise(){try{mp=MediaPlayer.create(this,Settings.System.DEFAULT_ALARM_ALERT_URI);if(mp!=null){mp.setLooping(true);mp.start();}}catch(Exception ignored){}vib=(Vibrator)getSystemService(VIBRATOR_SERVICE);if(vib!=null){if(Build.VERSION.SDK_INT>=26)vib.vibrate(VibrationEffect.createWaveform(new long[]{0,900,250,900,250,1300},0));else vib.vibrate(new long[]{0,900,250,900,250,1300},0);}}void restartNoise(){stopNoise();startNoise();warn.setText("🚨 Dernier rappel : vérifie immédiatement.");}void stopNoise(){try{if(mp!=null){mp.stop();mp.release();mp=null;}}catch(Exception ignored){}try{if(vib!=null)vib.cancel();}catch(Exception ignored){}}public void onDestroy(){stopNoise();handler.removeCallbacksAndMessages(null);super.onDestroy();}}
